commandLine.original:
$title = 'ניהול חשבונות דיירים - דרישות אפליקציה';
$searchGlobs = @(
  "$env:APPDATA\Code\User\workspaceStorage\*\chatSessions\*.jsonl",
  "$env:APPDATA\Code - Insiders\User\workspaceStorage\*\GitHub.copilot-chat\transcripts\*.jsonl",
  "$env:APPDATA\Code - Insiders\User\workspaceStorage\*\chatSessions\*.jsonl"
);
$files = foreach ($g in $searchGlobs) { Get-ChildItem -Path $g -File -ErrorAction SilentlyContinue };
$files = $files | Sort-Object -Property FullName -Unique;
if (-not $files) { 'No candidate files found.'; exit 0 }
$matches = foreach ($f in $files) {
  Select-String -Path $f.FullName -Pattern $title -SimpleMatch -Encoding utf8 -ErrorAction SilentlyContinue |
    Select-Object @{n='Path';e={$_.Path}}, @{n='LineNumber';e={$_.LineNumber}}, @{n='Snippet';e={ if ($_.Line.Length -gt 140) { $_.Line.Substring(0,140) + '…' } else { $_.Line } }}, @{n='LastWriteTime';e={$f.LastWriteTime}}
};
if (-not $matches) { "No matches for exact title: $title"; exit 0 }
'Matches:';
$matches | Sort-Object Path, LineNumber | Format-Table -AutoSize;
'';
'Newest matching file:';
$matches | Sort-Object LastWriteTime -Descending | Select-Object -First 1 Path, LastWriteTime | Format-Table -AutoSize;

