$titleCodes = @(0x05E0,0x05D9,0x05D4,0x05D5,0x05DC,0x0020,0x05D7,0x05E9,0x05D1,0x05D5,0x05E0,0x05D5,0x05EA,0x0020,0x05D3,0x05D9,0x05D9,0x05E8,0x05D9,0x05DD,0x0020,0x002D,0x0020,0x05D3,0x05E8,0x05D9,0x05E9,0x05D5,0x05EA,0x0020,0x05D0,0x05E4,0x05DC,0x05D9,0x05E7,0x05E6,0x05D9,0x05D4)
$title = -join ($titleCodes | ForEach-Object { [char]$_ })

$globs = @(
  "$env:APPDATA\\Code\\User\\workspaceStorage\\*\\chatSessions\\*.jsonl",
  "$env:APPDATA\\Code - Insiders\\User\\workspaceStorage\\*\\GitHub.copilot-chat\\transcripts\\*.jsonl",
  "$env:APPDATA\\Code - Insiders\\User\\workspaceStorage\\*\\chatSessions\\*.jsonl"
)

$files = foreach ($g in $globs) { Get-ChildItem -Path $g -File -ErrorAction SilentlyContinue }
$files = $files | Sort-Object FullName -Unique

$matches = @()
foreach ($f in $files) {
  $m = Select-String -Path $f.FullName -SimpleMatch -Pattern $title -Encoding UTF8 -ErrorAction SilentlyContinue
  foreach ($hit in $m) {
    $snippet = $hit.Line
    if ($snippet.Length -gt 180) { $snippet = $snippet.Substring(0,180) + '...' }
    $matches += [pscustomobject]@{
      Path = $f.FullName
      LastWriteTime = $f.LastWriteTime
      LineNumber = $hit.LineNumber
      Snippet = $snippet
    }
  }
}

if (-not $matches -or $matches.Count -eq 0) {
  Write-Output 'NO_MATCHES'
} else {
  Write-Output 'MATCHES:'
  $matches | Sort-Object LastWriteTime -Descending | Select-Object -First 30 | Format-Table -AutoSize
  Write-Output 'NEWEST_MATCH:'
  $matches | Sort-Object LastWriteTime -Descending | Select-Object -First 1 | Format-List
}
